     5	export async function resolveSkillContent(
     6	  skills: string[],
     7	  options: { gitMasterConfig?: GitMasterConfig; browserProvider?: BrowserAutomationProvider, disabledSkills?: Set<string>, directory?: string }
     8	): Promise<{ content: string | undefined; contents: string[]; error: string | null }> {
     9	  if (skills.length === 0) {
    10	    return { content: undefined, contents: [], error: null }
    11	  }
