cat > /tmp/skill-short-name-repro.ts <<'EOF'
import { createSkillTool } from "/workspace/oh-my-openagent/src/tools/skill/tools"
import { executeSlashCommand } from "/workspace/oh-my-openagent/src/hooks/auto-slash-command/executor"
import type { LoadedSkill } from "/workspace/oh-my-openagent/src/features/opencode-skill-loader/types"

function skill(name: string, template: string): LoadedSkill {
  return {
    name,
    resolvedPath: `/tmp/${name}`,
    definition: {
      name,
      description: `Skill ${name}`,
      template,
    },
    scope: "config",
  }
}

const systematic = skill("superpowers/systematic-debugging", "Follow the systematic debugging process.")
const tool = createSkillTool({ skills: [systematic], commands: [] })
const context = { agent: "test-agent" }

async function expectToolSuccess(name: string) {
  const result = await tool.execute({ name }, context)
  if (!String(result).includes("Follow the systematic debugging process.")) {
    throw new Error(`${name} resolved without expected content`)
  }
  console.log(`tool-success:${name}`)
}

await expectToolSuccess("superpowers/systematic-debugging")
await expectToolSuccess("systematic-debugging")
await expectToolSuccess("/superpowers:systematic-debugging")

const slashShort = await executeSlashCommand(
  { command: "systematic-debugging", args: "", raw: "/systematic-debugging" },
  { skills: [systematic] }
)
if (!slashShort.success || !slashShort.replacementText?.includes("Follow the systematic debugging process.")) {
  throw new Error(`slash short-name failed: ${slashShort.error}`)
}
console.log("slash-success:systematic-debugging")

const slashNamespace = await executeSlashCommand(
  { command: "superpowers:systematic-debugging", args: "", raw: "/superpowers:systematic-debugging" },
  { skills: [systematic] }
)
if (!slashNamespace.success || !slashNamespace.replacementText?.includes("Follow the systematic debugging process.")) {
  throw new Error(`slash namespace failed: ${slashNamespace.error}`)
}
console.log("slash-success:superpowers:systematic-debugging")

const ambiguousTool = createSkillTool({
  skills: [
    skill("superpowers/systematic-debugging", "first"),
    skill("other/systematic-debugging", "second"),
  ],
  commands: [],
})
try {
  await ambiguousTool.execute({ name: "systematic-debugging" }, context)
  throw new Error("ambiguous short name unexpectedly resolved")
} catch (error) {
  const message = error instanceof Error ? error.message : String(error)
  if (!message.includes("Skill or command \"systematic-debugging\" not found")) {
    throw error
  }
  console.log("ambiguous-short-name:rejected")
}
EOF
