export interface NamedSkill {
  name: string
}

function normalizeComparableName(name: string): string {
  return name.toLowerCase()
}

export function normalizeSkillRequestName(name: string): string {
  const trimmed = name.trim().replace(/^\//, "")
  if (!trimmed.includes("/") && trimmed.includes(":")) {
    return trimmed.replace(":", "/")
  }
  return trimmed
}

export function getSkillShortName(skillName: string): string {
  const normalizedName = normalizeSkillRequestName(skillName)
  const separatorIndex = normalizedName.lastIndexOf("/")
  return separatorIndex >= 0 ? normalizedName.slice(separatorIndex + 1) : normalizedName
}

export function findSkillByExactName<T extends NamedSkill>(skills: T[], requestedName: string): T | undefined {
  const normalizedRequest = normalizeComparableName(normalizeSkillRequestName(requestedName))
  return skills.find((skill) => normalizeComparableName(normalizeSkillRequestName(skill.name)) === normalizedRequest)
}

export function findSkillByShortName<T extends NamedSkill>(skills: T[], requestedName: string): T | undefined {
  const normalizedRequest = normalizeSkillRequestName(requestedName)
  if (normalizedRequest.includes("/")) {
    return undefined
  }

  const comparableRequest = normalizeComparableName(normalizedRequest)
  const matches = skills.filter((skill) =>
    normalizeComparableName(getSkillShortName(skill.name)) === comparableRequest
  )

  return matches.length === 1 ? matches[0] : undefined
}

